import java.util.concurrent.*;
import java.util.*;

public class ExecutorExample {
    public static void main(String[] args) throws Exception {
        // 1. Single thread executor
        System.out.println("=== Single Thread Executor ===");
        ExecutorService single = Executors.newSingleThreadExecutor();

        single.execute(() -> {
            System.out.println("Single: Task 1 on " + Thread.currentThread().getName());
        });
        single.execute(() -> {
            System.out.println("Single: Task 2 on " + Thread.currentThread().getName());
        });

        single.shutdown();

        // 2. Fixed thread pool
        System.out.println("=== Fixed Thread Pool (3 threads) ===");
        ExecutorService fixed = Executors.newFixedThreadPool(3);

        for (int i = 0; i < 10; i++) {
            final int taskId = i;
            fixed.execute(() -> {
                System.out.println("Task " + taskId + " on " + Thread.currentThread().getName());
                try {
                    Thread.sleep(100);  // Simulate work
                } catch (InterruptedException e) {
                    e.printStackTrace();
                }
            });
        }

        fixed.shutdown();

        // 3. Cached thread pool
        System.out.println("=== Cached Thread Pool ===");
        ExecutorService cached = Executors.newCachedThreadPool();

        for (int i = 0; i < 5; i++) {
            final int taskId = i;
            cached.execute(() -> {
                System.out.println("Cached: Task " + taskId + " on " + Thread.currentThread().getName());
            });
        }

        cached.shutdown();

        // 4. Scheduled thread pool
        System.out.println("=== Scheduled Thread Pool ===");
        ScheduledExecutorService scheduled = Executors.newScheduledThreadPool(2);

        // Schedule a task with delay
        scheduled.schedule(() -> {
            System.out.println("Scheduled: Task executed after 1 second delay");
        }, 1, TimeUnit.SECONDS);

        // Schedule periodic task (run every 500ms, start after 200ms)
        ScheduledFuture<?> future = scheduled.scheduleAtFixedRate(() -> {
            System.out.println("Periodic: " + System.currentTimeMillis());
        }, 200, 500, TimeUnit.MILLISECONDS);

        // Let it run for 2 seconds
        Thread.sleep(2000);
        future.cancel(false);  // Stop the periodic task
        scheduled.shutdown();

        // 5. Submitting tasks with Future
        System.out.println("=== Future (Return Values) ===");
        ExecutorService futurePool = Executors.newFixedThreadPool(3);

        // Submit tasks that return values
        Future<Integer> future1 = futurePool.submit(() -> {
            Thread.sleep(500);
            return 42;
        });

        Future<Integer> future2 = futurePool.submit(() -> {
            Thread.sleep(300);
            return 100;
        });

        // Get results (blocks until ready)
        System.out.println("Future1 result: " + future1.get());
        System.out.println("Future2 result: " + future2.get());

        futurePool.shutdown();

        // 6. Invoke all tasks
        System.out.println("=== Invoke All ===");
        ExecutorService invokePool = Executors.newFixedThreadPool(3);

        List<Callable<String>> tasks = new ArrayList<>();
        for (int i = 0; i < 5; i++) {
            final int id = i;
            tasks.add(() -> {
                Thread.sleep(100);
                return "Task " + id + " done!";
            });
        }

        // Execute all tasks and get all results
        List<Future<String>> results = invokePool.invokeAll(tasks);
        for (Future<String> result : results) {
            System.out.println(result.get());
        }

        invokePool.shutdown();

        // 7. Shutdown properly
        System.out.println("=== Shutdown ===");
        ExecutorService pool = Executors.newFixedThreadPool(2);

        pool.execute(() -> System.out.println("Task 1"));
        pool.execute(() -> System.out.println("Task 2"));
        pool.execute(() -> System.out.println("Task 3"));

        pool.shutdown();  // No new tasks accepted

        try {
            // Wait for existing tasks to finish
            if (!pool.awaitTermination(5, TimeUnit.SECONDS)) {
                pool.shutdownNow();  // Force shutdown
            }
        } catch (InterruptedException e) {
            pool.shutdownNow();
        }

        System.out.println("All pools shut down!");
    }
}

phase2.brokenCode:
import java.util.concurrent.*;

public class Test {
    public static void main(String[] args) {
        ExecutorService pool = Executors.newFixedThreadPool(2);

        // Forgetting to shutdown
        pool.execute(() -> System.out.println("Hello"));

        // Program ends but pool still running!
        System.out.println("Done");
    }
}

phase2.explanation:
The ExecutorService's threads are non-daemon threads. They keep the JVM running even after main() ends!

The program will hang indefinitely because the pool is still active.

FIX: Always shutdown the pool:

pool.shutdown();  // Graceful shutdown

Or use try-with-resources (Java 19+):
try (ExecutorService pool = Executors.newFixedThreadPool(2)) {
    pool.execute(() -> System.out.println("Hello"));
}

Or shutdown and wait:
pool.shutdown();
pool.awaitTermination(5, TimeUnit.SECONDS);

Always clean up your thread pools!

